package be.schaubroeck.lpb.rkm.rekenmotor.rsz;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmTijdperk;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.RszppoKategorie;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.Kengetal;
import be.schaubroeck.lpb.tools.rsz.dmfa.KengetalDmfa;
import be.schaubroeck.lpb.tools.rsz.dmfappl.KengetalDmfappl;

public final class WerknemersKengetalFactory {
    private WerknemersKengetalFactory() {
    }

    public static Kengetal getKengetal(RekenTijd rekenTijd, DmfapplWnkengetal kengetal) {
        if (rekenTijd.isDmfa()) {
            return new KengetalDmfa(kengetal);
        } else {
            return new KengetalDmfappl(kengetal);
        }
    }

    public static Kengetal getKengetal(RkmTijdperk tijdperk, DmfapplWnkengetal kengetal) {
        if (tijdperk == RkmTijdperk.DMFA) {
            return new KengetalDmfa(kengetal);
        } else {
            return new KengetalDmfappl(kengetal);
        }
    }


    public static boolean isContractueelGeneesheerInOpleidingSpecialist(RekenTijd rekenTijd, DmfapplWnkengetal kengetal, WerkgeversCategorie categorie) {
        return getKengetal(rekenTijd, kengetal).isContractueelGeneesheerInOpleidingSpecialist(kengetal, categorie);
    }

    public static boolean isStudent(Opper opper, RkmTijdperk tijdperk) {
        Rszppo rszppo = opper.getRszppo();
        if (tijdperk == RkmTijdperk.RSZPPO) {
            return rszppo.getCategorie() == RszppoKategorie.STUDENT;
        } else {
            return getKengetal(tijdperk, rszppo.getWerknemersKengetal()).isStudent();
        }
    }

    public static boolean isAltijd95X(RekenTijd rekenTijd, DmfapplWnkengetal kengetal, DmfapplStatuutDmfappl statuut) {
        return getKengetal(rekenTijd, kengetal).isAltijd95X(statuut);
    }

    public static boolean isVrijwilligeBrandweer(RekenTijd rekenTijd, DmfapplWnkengetal kengetal, DmfapplStatuutDmfappl statuut) {
        return getKengetal(rekenTijd, kengetal).isVrijwilligeBrandweer(statuut);
    }

    public static boolean isNotLeerContract(RekenTijd rekenTijd, DmfapplWnkengetal kengetal) {
        return getKengetal(rekenTijd, kengetal).isNotLeerContract();
    }
}
